head.script:
scwin.nowDt = $c.date.getServerDateTime(); 
scwin.userId = $c.data.getMemInfo("userId"); 
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); 

scwin.afterSaveRetrieveYN = "YES";
scwin.examineOdrYn = 0;
scwin.allchecked = false;
scwin.lobranCd = "";

scwin.curRow = 0;

scwin.onpageload = async function () {
	const codeOptions = [
        { grpCd: "SD102", compID: "gr_results:cntrWtCondCd" } 
    ];
    $c.data.setCommonCode(codeOptions);

    const utilOptions = [
        {
            method: "getLuxeComboData",
            param1: "NcallWorkImplementEBC",
            param2: "retriveLobran2CodeList",
            param3: ["1"],
            compID: "acb_lobranCd"
        }
    ];
    await $c.data.setGauceUtil(utilOptions, function() {
        acb_lobranCd.setValue(scwin.loUpperLobranCd);

        // 테스트데이터
        // acb_lobranCd.setValue("6AA");
    });
};

scwin.onUdcCompleted = function () {
    scwin.f_initSearchCondition();
  	scwin.f_tabLocation();

};

scwin.ondataload = function () {

};

//-------------------------------------------------------------------------
// Function
//-------------------------------------------------------------------------
// 조회조건 초기화
scwin.f_initSearchCondition = function () { 
    scwin.f_setDatsetHeader();
    ed_dptIntendDd.setValue(scwin.nowDt);
    ed_dptIntendDd2.setValue(scwin.nowDt);
    acb_qryClsCd.setValue("N");

    // 테스트데이터
    // ed_dptIntendDd.setValue("20150101");
    // ed_dptIntendDd2.setValue("20150101");
    // ed_dptIntendDd.setValue("20170101");
    // ed_dptIntendDd2.setValue("20170110");
};

scwin.f_setDatsetHeader = function () {
    ds_search.removeAll();
	ds_search.insertRow();
};

// 조회
scwin.f_Retrieve = async function (flag) {
    // if (!await $c.gus.cfValidate([ed_dptIntendDd, ed_dptIntendDd2])) {	
    //     return;
    // }

    if (!await $c.gus.cfIsAfterDate(ed_dptIntendDd.getValue(), ed_dptIntendDd2.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ed_dptIntendDd.focus();
        return;
    }

    const cntrBox = dma_input.get("cntrBox");

    if (cntrBox != "" && (ed_cntrNo.getValue() != ""|| ed_cntrNo2.getValue() != "")) {
        await $c.gus.cfAlertMsg("컨테이너 다중검색의 경우 앞의 하얀 컨테이너박스의 내용을 삭제해주세요.");
        return;
    }

    if(!$c.util.isEmpty(cntrBox)) {
        ds_search.setCellData(0, "cntrBox", cntrBox);
    } else {
        ds_search.setCellData(0, "cntrBox", "");
    }


    if (scwin.flag == "1") {
        let e = await $c.sbm.execute(sbm_retrieve);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieve_submitdone(e);
        }
    } else {
        scwin.examineOdrYn = 0;
        ds_results.removeAll();
        let e = await $c.sbm.execute(sbm_retrieve);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieve_submitdone(e);
        }
    }
};

// 배차점소에 따른 object제어
scwin.f_tabLocation = function () {		
    // 부산지사일때만 모선/항차, OPERATOR활성화
    if (acb_lobranCd.getValue() == "6AA") {
        spn_rsltsTable_6AA.show();
    } else {
        ed_shpCoCd.setValue("");
        ed_tmlVsslPortcnt.setValue("");
        spn_rsltsTable_6AA.hide();
    }
};

// 조회
scwin.f_RetrieveVechl = async function () {  
    let e = await $c.sbm.execute(sbm_retrieveVehcl);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_retrieveVehcl_submitdone(e);
    }
};

// 저장
scwin.f_Save = async function (retrieveYn) {
    if (ds_results.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return false;
    }

    for (var i = 0; i < ds_results.getRowCount(); i++) {
		if (ds_results.getCellData(i, "vehclClntNo") === ds_results.getCellData(i, "bilgClntNo")) {
			await $c.gus.cfAlertMsg("오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
			return false;
		}

        if (acb_qryClsCd.getValue() == "N") {
            if (ds_results.getCellData(i, "dcScAmt") > 0 ) {
	    		if (ds_results.getCellData(i, "dcScNm") == "") {
	    			await $c.gus.cfAlertMsg("할인할증금액은 팝업을 띄워서 할인할증항목을 선택하고, 금액을 입력한 후, 저장하셔야 합니다");
	    			return false;
	    		}
	    	}
        }

	} 


    scwin.afterSaveRetrieveYN = retrieveYn;

    // 검색기여부가Y, 오더종류가C1, 미배차운송 건 알림메세지 추가 2013.05.23 곽광제과장 요청
    if (ds_results.getCellData(ds_results.getRowPosition(), "xrayTrgtYn") == 1 
       && ds_results.getCellData(ds_results.getRowPosition(), "xrayLupTrgtYn") == 0
       && ds_results.getCellData(ds_results.getRowPosition(), "odrKndCd") == "C1" 
       && ds_results.getCellData(ds_results.getRowPosition(), "transWrkIndictNo") == "") {
        var saveChk = await $c.win.confirm("검색기대상 화물이나 검색기오더 미생성 상태입니다.\n 그래도 배차하시겠습니까?");     
        if (saveChk) {
            let e = await $c.sbm.execute(sbm_save);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                await scwin.sbm_save_submitdone(e);
            } else {
                const message =  e.responseJSON.resultDataSet[1].Msg
                const parts = message.split("■");
                let msgCode, msgContent;
                if (parts.length > 0) {
                    msgCode = parts[0].trim();
                    msgContent = parts.slice(1).join("\n").trim();
                }
                await $c.win.alert("메시지코드: " + msgCode + "\n" + "메시지내용: " + msgContent);
            }
        } else {
            return false;
        }
    } else {
        let e = await $c.sbm.execute(sbm_save);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            await scwin.sbm_save_submitdone(e);
        } else {
            const message =  e.responseJSON.resultDataSet[1].Msg
            const parts = message.split("■");
            let msgCode, msgContent;
            if (parts.length > 0) {
                msgCode = parts[0].trim();
                msgContent = parts.slice(1).join("\n").trim();
            }
            await $c.win.alert("메시지코드: " + msgCode + "\n" + "메시지내용: " + msgContent);
        }
    }
};

// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        // inObj가 코드 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        // inObj가 코드명 필드일 경우 팝업
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    switch (disGubun) {
        case 4:
            udc_clntNo.setSelectId("retrieveCarKindCoClntInfo_tpro");    
            rtnList = await udc_clntNo.cfCommonPopUpAsync(
                                                              ''	                                // XML상의 SELECT ID	
                                                            , pCode					                // 화면에서의 ??? Code Element의	Value
                                                            , pName					                // 화면에서의 ??? Name Element의	Value
                                                            , pClose					            // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                            , null					                // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                            , null					                // Title순서	
                                                            , null				                    // 보여주는 각 컬럼들의 폭	
                                                            , null					                // 컬럼중에서 숨기는	컬럼 지정	
                                                            , DsConstants.PCHS_CLNT_CLS_CD_HIRECAR  // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                            , null					                // POP-UP뛰을때 원도우의	사용자 정의	폭
                                                            , null					                // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                            , null					                // 윈도우 위치 Y좌표	
                                                            , null					                // 윈도우 위치 X좌표
                                                            , null					                // 중복체크여부	("F")
                                                            , pAllSearch					        // 전체검색허용여부	("F")
                                                            ,"협력업체,협력업체코드/명,"			  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                        );
            $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);
        break;
        case 5: // 배차담당자
            udc_alloccarPicId.setSelectId("retrieveUserInfo_tpro"); 
            rtnList = await udc_alloccarPicId.cfCommonPopUpAsync(
                                                                      ''		            // XML상의 SELECT ID	
                                                                    , pCode					// 화면에서의 ??? Code Element의	Value
                                                                    , pName					// 화면에서의 ??? Name Element의	Value
                                                                    , pClose				// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                                    , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                    , null					// Title순서	
                                                                    , null					// 보여주는 각 컬럼들의 폭	
                                                                    , null					// 컬럼중에서 숨기는	컬럼 지정	
                                                                    , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                                    , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                                                    , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                                    , null					// 윈도우 위치 Y좌표	
                                                                    , null					// 윈도우 위치 X좌표
                                                                    , null					// 중복체크여부	("F")
                                                                    , pAllSearch			// 전체검색허용여부	("F")
                                                                    , null					// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                                );
            $c.gus.cfSetReturnValue(rtnList, ed_alloccarPicId, ed_alloccarPicNm);
        break;
        case 7:
            udc_shortChassNo.setSelectId("retrieveChassisNo_tpro");
            rtnList = await udc_shortChassNo.cfCommonPopUpAsync(
                                                                      ''                     // XML상의 SELECT ID
                                                                    , pCode                  // 화면에서의 ??? Code Element의  Value
                                                                    , pName                  // 화면에서의 ??? Name Element의  Value
                                                                    , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부  (T:Close,F:Opened)
                                                                    , null                   // 검색 결과  컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                    , null                   // Title순서
                                                                    , null                   // 보여주는 각 컬럼들의 폭
                                                                    , null                   // 컬럼중에서 숨기는  컬럼 지정
                                                                    , 'C'                    // SQL절의 WHERE절에  원하는 조건을 선택함 MAX:8개까지 가능
                                                                    , null                   // POP-UP뛰을때 원도우의  사용자 정의 폭
                                                                    , null                   // POP-UP뛰을때 우도우의  사용자 정의 높이
                                                                    , null                   // 윈도우 위치 Y좌표
                                                                    , null                   // 윈도우 위치 X좌표
                                                                    , null                   // 중복체크여부 ("F")
                                                                    , 'F'                    // 전체검색허용여부 ("F")
                                                                    , null                   // POP-UP Window Title 검색어1,2   ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                                );
            $c.gus.cfSetReturnValue(rtnList, ed_shortChassNo, hid_chassisNo); 
            if (rtnList != null) {
                hid_chassisEqCd.setValue(rtnList[4]);
                hid_chassisKndCd.setValue(rtnList[2]);
            }
        break;
        case 8: // 협력업체(차량매입) 계약승인 조회

            udc_vehclClntNo.setSelectId("retrieveCarKindCoClntInfo_tpro"); 
            rtnList = await udc_vehclClntNo.cfCommonPopUpAsync(
                                                                      ''	                                // XML상의 SELECT ID	
                                                                    , pCode					                // 화면에서의 ??? Code Element의	Value
                                                                    , pName					                // 화면에서의 ??? Name Element의	Value
                                                                    , pClose					            // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                                                    , null					                // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                    , null					                // Title순서	
                                                                    , null					                // 보여주는 각 컬럼들의 폭	
                                                                    , null				                    // 컬럼중에서 숨기는	컬럼 지정	
                                                                    , DsConstants.PCHS_CLNT_CLS_CD_HIRECAR  // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                                                    , null					                // POP-UP뛰을때 원도우의	사용자 정의	폭
                                                                    ,  null					                // POP-UP뛰을때 우도우의	사용자 정의	높이	
                                                                    , null					                // 윈도우 위치 Y좌표	
                                                                    , null					                // 윈도우 위치 X좌표
                                                                    , null					                // 중복체크여부	("F")
                                                                    , pAllSearch					        // 전체검색허용여부	("F")
                                                                    ,"협력업체,협력업체코드/명,"			 // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                                );
            $c.gus.cfSetReturnValue(rtnList, ed_vehclClntNo, ed_vehclClntNm);
        break;   		
        default:
        break;
    }
};

// 그리드에서 입력된 코드/명칭 정보로  조회 (Grid PopUp)
scwin.f_openCommPopUpGrid = async function (disGubun, row, pClose) {

    // 선언부
    var rtnList;
    var pCode = "";
    var pName = "";

    switch (disGubun) {
      case 2:
            pCode = ds_results.getCellData(row, "chassShortNo");
            udc_gridComCode.setSelectId("retrieveChassisNo_tpro");
            rtnList = await udc_gridComCode.cfCommonPopUpAsync(
                                                                      ''                     // XML상의 SELECT ID
                                                                    , pCode                  // 화면에서의 ??? Code Element의  Value
                                                                    , pName                  // 화면에서의 ??? Name Element의  Value
                                                                    , pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부  (T:Close,F:Opened)
                                                                    , null                   // 검색 결과  컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                                                    , null                   // Title순서
                                                                    , null                   // 보여주는 각 컬럼들의 폭
                                                                    , null                   // 컬럼중에서 숨기는  컬럼 지정
                                                                    , 'C'                    // SQL절의 WHERE절에  원하는 조건을 선택함 MAX:8개까지 가능
                                                                    , null                   // POP-UP뛰을때 원도우의  사용자 정의 폭
                                                                    , null                   // POP-UP뛰을때 우도우의  사용자 정의 높이
                                                                    , null                   // 윈도우 위치 Y좌표
                                                                    , null                   // 윈도우 위치 X좌표
                                                                    , null                   // 중복체크여부 ("F")
                                                                    , 'F'                    // 전체검색허용여부 ("F")
                                                                    , null                   // POP-UP Window Title 검색어1,2   ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                                                );
            $c.gus.cfSetGridReturnValue(rtnList, ds_results, row, "chassShortNo", "");

            ds_results.setCellData(row, "chassisEqCd", rtnList[4]);
            ds_results.setCellData(row, "chassisKndCd", rtnList[2]);

            scwin.f_checkChasisNo(row);
        break;
        default:
        break;
    }
};

// 프린트
scwin.f_print = async function (gubun) {
    var v_msg = "";

    if (ds_results.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, new Array("오더"));
        return;
    } else {
        var v_lobranCd 		= acb_lobranCd.getValue();
        var v_odrNo 		= ds_results.getCellData(ds_results.getRowPosition(), "odrNo");
        var v_cntrSeq 		= ds_results.getCellData(ds_results.getRowPosition(), "cntrSeq");
        var v_cntrNo 		= ds_results.getCellData(ds_results.getRowPosition(), "cntrNo");
        var v_cargoClsCd 	= "C";
        var v_wrkStDt 		= ds_results.getCellData(ds_results.getRowPosition(), "wrkStDt");
        var v_wrkEndDt 		= ds_results.getCellData(ds_results.getRowPosition(), "wrkEndDt");
        var v_dptWrkPlCd 	= ds_results.getCellData(ds_results.getRowPosition(), "dptWrkPlCd");
        var v_crryinoutIntendNo	= ds_results.getCellData(ds_results.getRowPosition(), "crryinoutIntendNo");

        switch (gubun) {
            case 1:
                if ($c.gus.cfIsNull(v_odrNo)) {
                    await $c.gus.cfAlertMsg("오더를 선택하십시요");
                    return;
                }

                // 오더sheet 담당자 지정함.
                ds_odrSheet.setCellData(0, "odrNo", ds_results.getCellData(ds_results.getRowPosition(), "odrNo"));
                ds_odrSheet.setCellData(0, "prtPicId", scwin.userId); 

                let e = await $c.sbm.execute(sbm_saveOrdersheet);
                if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {

                }

                const obj = {
                    reportName: "/ds/op/wrkplan/transwrkplan/op_202_02_03r.ozr",
                    odiName : "op_202_02_03r",
                    odiParam: {
                        odrNo : v_odrNo,
                    },
                    viewerParam: {
                        zoom : "100",
                    },
                    formParam: {}
                };

                await scwin.openPopup(obj);
            break;
            case 2:
                if ($c.gus.cfIsNull(v_crryinoutIntendNo)) {
                    await $c.gus.cfAlertMsg("배차후 동부CY인 경우만 배차지시서 발행이 가능합니다 (반출입예정번호가 없습니다)");
                    return;
                }

                const data = {
                    reportName: "/ds/op/wrkplan/transwrkplan/op_301_01_05r.ozr",
                    odiName : "op_301_01_05r",
                    odiParam: {
                        crryinoutIntendNo : v_crryinoutIntendNo,
                    },
                    viewerParam: {
                        zoom : "100",
                    },
                    formParam: {}
                };

                await scwin.openPopup(data);
            break;
            default:
            break;
        }
    }
};

scwin.openPopup = async function(data) {
