// 저장(A/S)
scwin.f_SaveAndAutoEDI = async function (flag) {
    if (acb_qryClsCd.getValue() == "Y") {
        await $c.gus.cfAlertMsg("배차후에는 이용할 수 없습니다.");
        return false;
    }

    for (var i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getCellData(i, "vehclClntNo") == ds_results.getCellData(i, "bilgClntNo")) {
            await $c.gus.cfAlertMsg("오더의 청구거래처와 협력 운송업체가 동일한 경우 저장 할 수 없습니다.");
            return false;
        }
    } 

    var arrParam = new Array();
    var arryCnt = 0;

    for (var i = 0; i < ds_results.getRowCount(); i++) {
        if (ds_results.getRowStatus(i) == "U") {
            arrParam[arryCnt] = i;
            arryCnt++;

        }
    }


    await scwin.f_Save("NO");

    for (var i = 0; i < arrParam.length; i++) {
        if (ds_results.getCellData(arrParam[i], "vehclNo") == "") {
            await $c.gus.cfAlertMsg("컨테이너 "+ds_results.getCellData(arrParam[i], "cntrNo") + " 는 차량번호가 없어서 전송할 수 없습니다." );
            continue;
        } else {
            if (ds_results.getCellData(arrParam[i], "crryinEdiFlag") == "N" && ds_results.getCellData(arrParam[i], "crryoutEdiFlag") == "N" ) {
                await $c.gus.cfAlertMsg("컨테이너 "+ds_results.getCellData(arrParam[i], "cntrNo")
                            +", "+ds_results.getCellData(arrParam[i], "dptWrkPlNm")
                            +", "+ds_results.getCellData(arrParam[i], "arvWrkPlNm")
                            +" 는 EDI등록 대상이 아닙니다");
                continue;
            }
            if ((ds_results.getCellData(arrParam[i], "crryoutEdiType") != "CO" && ds_results.getCellData(arrParam[i], "crryoutEdiType") != "CD")
                && (ds_results.getCellData(arrParam[i], "crryinEdiType") != "CO" && ds_results.getCellData(arrParam[1], "crryinEdiType") != "CD")) {
                await $c.gus.cfAlertMsg("컨테이너 " + ds_results.get(arrParam[i], "cntrNo")
                            +", "+ds_results.getCellData(arrParam[i], "dptWrkPlNm")
                            +", "+ds_results.getCellData(arrParam[i], "arvWrkPlNm")
                            +" 는 EDI등록 대상이 아닙니다");
                continue;
            }

            if (flag == "AUTO") {
                scwin.f_crryInOutEDI(false, true, true, arrParam[i], true);
            } else if (flag == "MANUAL") {
                scwin.f_crryInOutEDI(false, false, false, arrParam[i], true);
            }
        }
    }

    scwin.f_Retrieve();
};

// 샤시번호 1111 체크
scwin.f_checkChasisNo = async function (row) {
    if (ds_results.getCellData(row, "posnClsCd") =="W" || ds_results.getCellData(row, "posnClsCd")=="J" ) {
        if (ds_results.getCellData(row, "chassShortNo") == "1111") {
