//  운송물량을 선택했을시 이벤트
scwin.f_selectWrkTrans = async function (colid) {
    var rowIndex = $c.gus.cfIsNull(ds_results.getRowPosition()) ? 0 : ds_results.getRowPosition();
    if (colid == "chk" && ds_results.getCellData(rowIndex, "chk") == 1) {

        if (ds_results.getCellData(rowIndex, "dptWrkPlClsCd") == "R" || ds_results.getCellData(rowIndex, "arvWrkPlClsCd") == "R") {
        }

        if (ds_results.getCellData(rowIndex, "dptWrkPlClsCd") == "C") {
            if (await $c.gus.cfAlertMsg("반출은 반출처리시 자동으로 배차정보가 생성됩니다.")) {
                //ds_results.Undo(ds_results.RowPosition);
                //gr_results.Focus();
                gr_results.setFocusedCell(rowIndex, 'chassShortNo');
                ds_results.undoRow(rowIndex);
                return;
            }
        }
    }

    // 작업지시번호가 있으면 체크박스를 비활성화 시킨다
    if (ds_results.getCellData(rowIndex, "transWrkIndictNo") != "") {
        // gr_results.ColumnProp('chk', 'Edit') = "None";
        gr_results.setColumnReadOnly("chk", true); 
        if (ds_results.getCellData(ds_results.getRowPosition(), "chk") == 1) { // 체크가 있을경우
            // gr_results.ColumnProp('cntrWrkKndCd'	, 'Edit') = "True";
            // gr_results.ColumnProp('dcScNm'			, 'Edit') = "True";
            gr_results.setColumnReadOnly("cntrWrkKndCd", false); 
            gr_results.setColumnReadOnly("dcScNm", false); 
        } else {
            // gr_results.ColumnProp('cntrWrkKndCd'	, 'Edit') = "None";
            // gr_results.ColumnProp('dcScNm'			, 'Edit') = "None";
            gr_results.setColumnReadOnly("cntrWrkKndCd", true); 
            gr_results.setColumnReadOnly("dcScNm", true); 
        }
    } else { // 작업지시가 아직 없는경우
        // gr_results.ColumnProp('chk', 'Edit') = "";
        gr_results.setColumnReadOnly("chk", false); 
        if (ds_results.getCellData(rowIndex, "chk") == 1) { // 체크가 있을 경우
            // gr_results.ColumnProp('cntrWrkKndCd'	, 'Edit') = "True";
            // gr_results.ColumnProp('dcScNm'			, 'Edit') = "True";
            gr_results.setColumnReadOnly("cntrWrkKndCd", false); 
            gr_results.setColumnReadOnly("dcScNm", false); 
        } else {
            // gr_results.ColumnProp('cntrWrkKndCd'	, 'Edit') = "None";
            // gr_results.ColumnProp('dcScNm'			, 'Edit') = "None";
            gr_results.setColumnReadOnly("cntrWrkKndCd", true); 
            gr_results.setColumnReadOnly("dcScNm", true);      
        }
    }

    if (ds_results.getCellData(rowIndex, "chk") == 1) {
        // 검색기 오더일시
        scwin.f_examineOdrSelect();
    }

    // 컬럼이 체크가 아니면 리턴
    if (colid != "chk")
        return;

    // 작업지시번호가 없으면
    if (ds_results.getCellData(rowIndex, "transWrkIndictNo") == "") {
        //체크가 풀리면 해당로우의 정보를 기존으로 되돌린다.
        if (ds_results.getCellData(rowIndex, "chk") != 1) {
            //ds_results.Undo(ds_results.getRowPosition());
            ds_results.undoRow(rowIndex);
        }
    }
};

//  검색기가 있는 운송물랴을 선택했을시의 이벤트
scwin.f_examineOdrSelect = async function () {
    if (ds_results.getCellData(ds_results.getRowPosition(), "xrayLupTrgtYn") > 0 && examineOdrYn == 0) {
        var confirmChk = await $c.win.confirm(["선택하신 운송물량은 검색기 운송물량이 있는 오더 입니다.\n\n선택한 오더와 검색기 오더를 같이 조회하여 작업지시를 해야 합니다. 조회 하시겠습니까?"]);
        if (!confirmChk) {
            // ds_results.Undo(ds_results.RowPosition);
            // gr_results.Focus();
            ds_results.undoRow(ds_results.getRowPosition());
            gr_results.focus();
            return;
        }
    } else {
        return;
    }

    scwin.f_RetrieveExamineOdr();
};

// 검색기 컨테이너 선택시 검색기 조회
scwin.f_RetrieveExamineOdr = function () {
    ds_dcScCd.removeAll();
    scwin.examineOdrYn = 1;

    if (ds_results.getCellData(ds_results.getRowPosition(), "chk") == 1) {
        if (ds_results.getCellData(ds_results.getRowPosition(), "xrayLupTrgtYn") == 1) {
            ds_results.setCellData(0, "cntrNo", ds_results.getCellData(ds_results.getRowPosition(), "cntrNo"));
            ds_results.setCellData(0, "odrNo", "");
            ed_cntrNo.setValue(ds_results.getCellData(ds_results.getRowPosition(), "cntrNo"));
            ed_odrNo.setValue("");
            scwin.f_Retrieve(1);
        }
    }
};

// 운송물량 모든 항목 체크
scwin.f_allChecked = async function (isCheck) {
    if (isCheck) {
        scwin.allchecked = false;
    }

    for (var i = 0; i < ds_results.getRowCount(); i++) {
        if (scwin.allchecked) {
            ds_results.setCellData(i, "chk", 0);
        } else {
            ds_results.setCellData(i, "chk", 1);
        }
    }

    if (scwin.allchecked) {
        scwin.allchecked = false;
    } else {
        await scwin.f_selectWrkTrans("chk");
        scwin.allchecked = true;
    }
    await scwin.f_selectWrkTrans("chk");

};

