//-------------------------------------------------------------------------
// Sbm submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = async function (e) {
    let rowCnt = ds_results.getRowCount(); 

    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg("조회된 데이터가 없습니다.");
        return false;
    } else {
        let sort_options = {};
        sort_options.sortIndex = "odrNo cntrSeq odrWrkPathSeq odrWrkStpSeq";
        sort_options.sortOrder = "1 1 1 1";  // 1: 오름차순
        ds_results.multisort(sort_options);
        ds_results.setRowPosition(0);
    }

    // 조회 건수를 출력한다.
    totalRows.setValue(rowCnt);
    var qryClsCd = ds_search.getCellData(0, "qryClsCd"); 
    if (qryClsCd == "Y") {
        qryClsCd = "1";
    } else {
        qryClsCd = "0";
    }

    // 배차인 경우는 수정 못하도록
    if (acb_qryClsCd.getValue() == "Y") {
        gr_results.setColumnReadOnly("vehclShortNo", true); 
        gr_results.setColumnReadOnly("vehclClntNm", true); 
        gr_results.setColumnReadOnly("cntrWtCondCd", true); 
        gr_results.setColumnReadOnly("chassShortNo", true); 
         btn_transCopino.removeClass("w2trigger_disabled");
        // 버튼 활성화
        $c.gus.cfEnableObjects([btn_transCopino]);

        // 가용차량 데이터셋 초기화
        ds_resultsVehcl.removeAll();
    } else {
        gr_results.setColumnReadOnly("vehclShortNo", false); 
        gr_results.setColumnReadOnly("vehclClntNm", false); 
        gr_results.setColumnReadOnly("cntrWtCondCd", false); 
        gr_results.setColumnReadOnly("chassShortNo", false); 
        btn_transCopino.addClass("w2trigger_disabled");
        // 버튼 비활성화
   //     $c.gus.cfDisableObjects([btn_transCopino]);

    }    
};

scwin.sbm_retrieveVehcl_submitdone = async function (e) { 
    let rowCnt = ds_resultsVehcl.getRowCount(); 

    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg("조회된 데이터가 없습니다.");
        return false;
    } else {
        ds_resultsVehcl.setRowPosition(0);
    }

    // 조회 건수를 출력한다.
    vehclRows.setValue(rowCnt);
};

scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
    if (scwin.afterSaveRetrieveYN == "YES") {
        let e = await $c.sbm.execute(sbm_retrieve);
        if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_retrieve_submitdone(e);
        }
    }
};

