scwin.gr_results_CustomFormatter = function(data, formattedData, rowIndex, colIndex) {
    let columnId =  $c.util.getComponent(this.id).getColumnID(colIndex);
    let val = data, color = "black";

    if (columnId == "crryoutEdiFlag") {
        var crryoutEdiType = ds_results.getCellData(rowIndex, "crryoutEdiType");
        var resultText = "";
        var typeText = "";

        if (data === "") {
            resultText = "미등록";
        } else if (data === "3") {
            resultText = "미전송";
        } else if (data === "1") {
            resultText = "전송완료";
        } else if (data === "0") {
            resultText = "전송대기";
        } else if (data === "5") {
            resultText = "필수항목오류";
        } else {
            resultText = ""; // 마지막 인자 "" 처리
        }

        if (crryoutEdiType === "CO") {
            typeText = "(COPINO)";
        } else if (crryoutEdiType === "CD") {
            typeText = "(COPI_CODECO)";
        } else {
            typeText = "";
        }
        color = "red";
        val = resultText + typeText;
    } else if (columnId == "crryinEdiFlag") {
        var crryinEdiType = ds_results.getCellData(rowIndex, "crryinEdiType");
        var resultText = "";
        var typeText = "";

        if (data === "") {
            resultText = "미등록";
        } else if (data === "3") {
            resultText = "미전송";
        } else if (data === "1") {
            resultText = "전송완료";
        } else if (data === "0") {
            resultText = "전송대기";
        } else if (data === "5") {
            resultText = "필수항목오류";
        } else {
            resultText = "";
        }

        if (crryinEdiType === "CO") {
            typeText = "(COPINO)";
        } else if (crryinEdiType === "CD") {
            typeText = "(COPI_CODECO)";
        } else {
            typeText = "";
        }
        color = "red";
        val = resultText + typeText;
    }

    gr_results.setCellColor(rowIndex, colIndex, color);

    return val;
};

