scwin.gr_results_onviewchange = async function (info) {
    var colId = info.colId;
    var colIndex = info.colIndex;
    var newValue = info.newValue;
    var oldValue = info.oldValue;
    var rowIndex = info.rowIndex;

    if(colId != "chk"){
        if (ds_results.getCellData(rowIndex, "dptWrkPlClsCd") == "C") {
            if(await $c.gus.cfAlertMsg("반출은 반출처리시 자동으로 배차정보가 생성됩니다.")){
                ds_results.undoRow(rowIndex);
                //gr_results.Focus();
            }
            return;
        }

        switch (colId) {
            case "vehclShortNo":
                if (ds_results.getCellData(rowIndex, "vehclShortNo") =="") {
                    ds_results.setCellData(rowIndex, "vehclShortNo", "");
                    ds_results.setCellData(rowIndex, "vehclNo", "");
                    ds_results.setCellData(rowIndex, "vehclClntNo", "");
                    ds_results.setCellData(rowIndex, "vehclClntNm", "");
                    ds_results.setCellData(rowIndex, "drvNm", "");
                    ds_results.setCellData(rowIndex, "mpNo", "");
                    ds_results.setCellData(rowIndex, "eqCd", "");
                    ds_results.setCellData(rowIndex, "chassShortNo", "");
                    ds_results.setCellData(rowIndex, "chassisEqCd", "");
                    ds_results.setCellData(rowIndex, "chassisKndCd", "");
                } else {
                    scwin.f_retrieveVehclInGrid();
                }
            break;
            case "chassShortNo": 
                scwin.f_openCommPopUpGrid(2, rowIndex, 'T');
            break;
        }
    }
};

scwin.gr_resultsVehcl_oncelldblclick = async function (rowIndex, columnIndex, columnId) {
	for (var i = 0; i < ds_results.getRowCount(); i++) {
		if (ds_results.getCellData(i, "vehclNo") == ds_resultsVehcl.getCellData(rowIndex, "vehclNo")) {
			await $c.gus.cfAlertMsg("선택하신 차량 " + ds_resultsVehcl.getCellData(rowIndex, "vehclNo") + " 는 이미 "
			      + ds_results.getCellData(i, "cntrNo") + " 컨테이너에 배차되었습니다" );
			return false;
			break;
		}
	}

	var ds_results_row = ds_results.getRowPosition();
	ds_results.setCellData(ds_results_row, "vehclShortNo", ds_resultsVehcl.getCellData(rowIndex, "vehclShortNo"));
	ds_results.setCellData(ds_results_row, "vehclNo", ds_resultsVehcl.getCellData(rowIndex, "vehclNo"));
	ds_results.setCellData(ds_results_row, "vehclClntNo", ds_resultsVehcl.getCellData(rowIndex, "vehclClntNo"));
	ds_results.setCellData(ds_results_row, "vehclClntNm", ds_resultsVehcl.getCellData(rowIndex, "vehclClntNm"));
	ds_results.setCellData(ds_results_row, "drvNm", ds_resultsVehcl.getCellData(rowIndex, "drvNm"));
	ds_results.setCellData(ds_results_row, "mpNo", ds_resultsVehcl.getCellData(rowIndex, "mpNo"));
	ds_results.setCellData(ds_results_row, "eqCd", ds_resultsVehcl.getCellData(rowIndex, "eqCd"));
	ds_results.setCellData(ds_results_row, "chassShortNo", ds_resultsVehcl.getCellData(rowIndex, "chassisShortCd"));
	ds_results.setCellData(ds_results_row, "chassisEqCd", ds_resultsVehcl.getCellData(rowIndex, "chassisEqCd"));
	ds_results.setCellData(ds_results_row, "chassisKndCd", ds_resultsVehcl.getCellData(rowIndex, "chassisKndCd"));
	ds_results.setCellData(ds_results_row, "posnClsCd", ds_resultsVehcl.getCellData(rowIndex, "posnClsCd"));

	scwin.f_checkChasisNo(ds_results_row);
};

